// Move child elements from head to body that don't belong in head
private void normaliseHead() {
    Element head = head();
    if (head == null) return;

    // Find elements in head that should be in body (anything that's not a head-specific element)
    // Head-specific elements include: base, link, meta, noscript, script, style, template, title
    // Any other elements should be moved to body
    List<Node> toMove = new ArrayList<Node>();
    for (Node node : head.childNodes) {
        if (node instanceof Element) {
            String nodeName = node.nodeName().toLowerCase();
            // Elements that are allowed in head according to HTML spec
            if (!isHeadElement(nodeName)) {
                toMove.add(node);
            } else if ("noscript".equals(nodeName)) {
                // Special case: content inside noscript in head should be moved to body
                Element noscriptEl = (Element) node;
                // Move all children of noscript to body
                List<Node> noscriptChildren = new ArrayList<Node>();
                for (Node child : noscriptEl.childNodes) {
                    noscriptChildren.add(child);
                }
                for (Node child : noscriptChildren) {
                    noscriptEl.removeChild(child);
                    body().appendChild(child);
                }
            }
        }
    }

    // Move non-head elements to body
    for (int i = toMove.size()-1; i >= 0; i--) {
        Node node = toMove.get(i);
        head.removeChild(node);
        body().appendChild(node);
    }
}

